UPDATE public.questions SET
  stimulus_text = 'While the study by researchers led by Dr. Smith, published in the "Journal of Psychological Research," showed that the brain''s capacity to form new memories does not decrease with age, they also discovered that this capacity may be linked to the number of times a person engages in mentally challenging activities.   Dr. Smith’s team found that older adults who regularly engaged in intellectually demanding activities, such as playing games, reading complex texts, and solving puzzles, had brains that were just as capable of forming new memories as those of much younger individuals. However, older adults who rarely or never engaged in such activities showed a noticeable decrease in their brain’s ability to form new memories.  The study’s findings suggest that ______',
  question_text = 'What does the study by Dr. Smith’s team suggest about the brain''s capacity to form new memories?',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"The brain''s capacity to form new memories is a fixed trait, and regular engagement in mentally challenging activities does not change this capacity.","is_correct":false,"explanation":"Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"The brain''s capacity to form new memories is influenced by a person''s age, and older adults are less likely to form new memories than younger individuals.","is_correct":false,"explanation":"Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"The brain''s capacity to form new memories is influenced by a person''s level of mental activity, and regular engagement in mentally challenging activities may help to preserve this capacity.","is_correct":true,"explanation":"Choice C matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"The brain''s capacity to form new memories is influenced by a person''s environment, and those who live in stimulating environments are more likely to form new memories than those who live in less stimulating environments.","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'C',
  explanation = 'The study suggests that the brain''s capacity to form new memories is not solely dependent on age, but rather is influenced by a person''s level of mental activity. Regular engagement in intellectually demanding activities may help to preserve this capacity. The passage states that "While the study by researchers led by Dr. Smith, published in the "Journal of Psychological Research," showed that the b…", which is the textual anchor for eliminating weaker choices. Choice C is correct because it aligns with that evidence: The brain''s capacity to form new memories is influenced by a person''s level of mental activity, and …. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
