  stimulus_type = NULL,
  options = '[{"id":"A","text":"People should learn to avoid stress at all costs.","is_correct":false,"explanation":"Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"People should not be afraid to ask for help when they are feeling stressed.","is_correct":true,"explanation":"Choice B matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"People should focus on overcoming stress rather than avoiding it.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"Stress is a normal part of life and should not be avoided.","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'B',
  explanation = 'The main point of the passage is that people should not be afraid to ask for help when they are feeling stressed. The author argues that people often feel overwhelmed by stress and believe that they have to overcome it on their own. The author suggests that this is incorrect and that there are many things that people can do to manage stress effectively. The author does not suggest that people should avoid stress at all costs, focus on overcoming stress rather than avoiding it, or that stress is a normal part of life and should not be avoided. The passage states that "The author of the passage suggests that the most common response to a stressful situation is to avoid it. This is becaus…", which is the textual anchor for eliminating weaker choices. Choice B is correct because it aligns with that evidence: People should not be afraid to ask for help when they are feeling stressed.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
