UPDATE public.questions SET
  stimulus_text = 'Although the novel’s plot is complex and ambitious, the novel’s greatest strength is the author’s ability to create richly imagined, unforgettable characters. For example, the central character, a young woman named Mina, is given a vivid and compelling portrait, filled with contradictions and nuances.  The author’s use of dialogue adds a depth of characterization, revealing their inner lives and motivations.',
  question_text = 'Which choice best explains the overall effect of the author''s focus on characterization in this passage?',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"The author emphasizes the complexity of the novel''s plot.","is_correct":false,"explanation":"Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"The author explores the importance of dialogue in fiction.","is_correct":false,"explanation":"Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"The author shows how the novel''s setting influences its characters.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"The author suggests that the novel''s most important feature is the creation of its characters.","is_correct":true,"explanation":"Choice D matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'D',
  explanation = 'The passage is focused on the author’s ability to create memorable characters. This is the main idea and the most important feature of the passage. The other choices may be true of the passage, but they are not the most important feature of the passage. The passage states that "Although the novel’s plot is complex and ambitious, the novel’s greatest strength is the author’s ability to create rich…", which is the textual anchor for eliminating weaker choices. Choice D is correct because it aligns with that evidence: The author suggests that the novel''s most important feature is the creation of its characters.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
