UPDATE public.questions SET
  stimulus_text = 'The author is trying to show that while the two writers are very different, they are still linked by the shared experiences that shaped their work. Both authors write about the difficult lives of Black people in America. Both authors use a powerful and evocative style that helps to bring their stories to life. Which choice best describes the author''s main point?',
  question_text = 'This passage suggests that the two writers',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"are similar in their use of language.","is_correct":true,"explanation":"Choice A matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"have different views of the American experience.","is_correct":false,"explanation":"Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"are both working to challenge conventional ideas about Black life in America.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"are both struggling to make sense of their personal experiences.","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'A',
  explanation = 'The passage discusses the authors'' shared experiences and their shared style of writing. This suggests that the author is trying to show how the two writers are similar. The passage states that "The author is trying to show that while the two writers are very different, they are still linked by the shared experien…", which is the textual anchor for eliminating weaker choices. Choice A is correct because it aligns with that evidence: are similar in their use of language.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"SYN","domain_id":"expression","opensat_index":1290,"opensat_domain":"Expression of Ideas","opensat_raw_id":"6860a419","opensat_difficulty":"Hard","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.927Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
