UPDATE public.questions SET
  stimulus_text = 'The author suggests that the popularity of the novel can be attributed to its depiction of a “destabilizing effect” on society. This is achieved through the novel’s use of “interpolated speech,” or characters’ speech interspersed within the narrative, to create a sense of realism. The author also suggests that this technique is a means for Black American authors to resist the constraints of “externally imposed literary conventions.”  Which of the following best describes the author’s overall purpose in this passage?',
  question_text = 'The author’s main purpose in this passage is to',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"explain the reasons for the popularity of the novel.","is_correct":true,"explanation":"Choice A matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"describe the narrative technique of interpolated speech.","is_correct":false,"explanation":"Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"demonstrate the author’s belief that Black American authors should resist literary conventions.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"argue that interpolated speech is a more realistic form of storytelling.","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'A',
  explanation = 'The author''s primary goal in the passage is to offer an explanation of the novel’s popularity, which is linked to both its realism and its defiance of literary conventions. While the passage briefly describes these ideas, the primary focus is on explaining the novel’s popularity. The passage states that "The author suggests that the popularity of the novel can be attributed to its depiction of a “destabilizing effect” on s…", which is the textual anchor for eliminating weaker choices. Choice A is correct because it aligns with that evidence: explain the reasons for the popularity of the novel.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"SYN","domain_id":"expression","opensat_index":1275,"opensat_domain":"Expression of Ideas","opensat_raw_id":"random_id_a3","opensat_difficulty":"Hard","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.927Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
